def fix_diacritics(text):
    """Ensure proper Romanian diacritics"""
    # The text should already have them, but let's make sure
    fixes = {
        'ţ': 'ț', 'Ţ': 'Ț',
        'ş': 'ș', 'Ş': 'Ș',
        'ă': 'ă', 'Ă': 'Ă',
        'â': 'â', 'Â': 'Â',
        'î': 'î', 'Î': 'Î',
    }
    result = text
    for k, v in fixes.items():
        result = result.replace(k, v)
    return result

def add_sarcastic_media_mention(title, content):
    """Add sarcastic VIDEO/FOTO/AUDIO/EXCLUSIV mentions to content"""
    has_video = bool(re.search(r'\b(VIDEO\.|VIDEO:)\b', title, re.IGNORECASE))
    has_foto = bool(re.search(r'\b(FOTO\.|FOTO:)\b', title, re.IGNORECASE))
    has_audio = bool(re.search(r'\b(AUDIO\.|AUDIO:)\b', title, re.IGNORECASE))
    has_exclusiv = bool(re.search(r'\b(EXCLUSIV\.|EXCLUSIV:)\b', title, re.IGNORECASE))

    sarcasms = []
    if has_video:
        sarcasms.append("VIDEO, pentru că nu-i suficient că s-a întâmplat, trebuie să-l vezi și tu ca să crezi.")
    if has_foto:
        sarcasms.append("FOTO, pentru că nu-i suficient că s-a întâmplat, trebuie să vezi poza ca să îți faci o idee.")
    if has_audio:
        sarcasms.append("AUDIO, pentru că nu-i suficient să citești, trebuie să asculți și tu.")
    if has_exclusiv:
        sarcasms.append("EXCLUSIV, ca la televizor, doar că e pe internet și nici nu e exclusiv.")

    if sarcasms:
        if content and len(content.strip()) > 10:
            content = content.rstrip('.') + '. ' + ' '.join(sarcasms)
        else:
            content = ' '.join(sarcasms)

    # Clean title of prefixes for processing but keep them for sarcasm
    clean_title = re.sub(r'^(VIDEO\.|FOTO\.|AUDIO\.|EXCLUSIV\.|VIDEO:|FOTO:|AUDIO:|EXCLUSIV:)\s*', '', title)

    return clean_title, content

