# Process all articles
processed = []
for a in articles_raw:
    title = a['title']
    content = a['content']

    # Apply replacements
    title = replace_cluj(title)
    title = replace_villages(title)
    content = replace_cluj(content)
    content = replace_villages(content)

    # Fix diacritics
    title = fix_diacritics(title)
    content = fix_diacritics(content)

    # Handle media prefixes
    title, content = add_sarcastic_media_mention(title, content)

    # If content is too short or empty, generate funny content
    if not content or len(content.strip()) < 20:
        content = generate_funny_content(title)

    # Ensure title ends with period
    if not title.endswith('.') and not title.endswith('!') and not title.endswith('?'):
        title = title + '.'

    processed.append({
        "title": title.strip(),
        "content": content.strip()
    })

# Deduplicate by normalized title
seen = set()
unique = []
for a in processed:
    key = a['title'].lower()[:80]
    if key not in seen:
        seen.add(key)
        unique.append(a)

print(f"Final unique articles: {len(unique)}")

# Save
with open('_data/news/data_cache/36cc03efe14d8324.html.json', 'w', encoding='utf-8') as f:
    json.dump(unique, f, ensure_ascii=False, indent=2)

